#include <bits/stdc++.h> 
using namespace std;
const int N=40005;
int n,m,a[N],vis[N],ans[N][5];
int main()
{
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>a[i];
		vis[a[i]]++;
	}
	for(int i=1;i<=n/9;i++)
	{
		int sum=0;
		for(int d=9*i+2;d<=n;d++)
		{
			int a=d-(9*i+1),b=a+2*i,c=d-i;
			sum+=(vis[a]*vis[b]);
			ans[c][3]+=(sum*vis[d]);
			ans[d][4]+=(sum*vis[c]);
//			cout<<a<<" "<<b<<" "<<c<<" "<<d<<"  c : "<<(sum*vis[d])<<"  d : "<<(sum*vis[c])<<"\n";
		}
		sum=0;
//		cout<<"----------------\n";
		for(int a=n-(9*i+1);a;a--)
		{
			int b=a+2*i,c=b+6*i+1,d=c+i;
			sum+=(vis[c]*vis[d]);
			ans[a][1]+=(sum*vis[b]);
			ans[b][2]+=(sum*vis[a]);
//			cout<<a<<" "<<b<<" "<<c<<" "<<d<<"  a : "<<(sum*vis[b])<<"  b : "<<(sum*vis[a])<<"\n";
		}
//		cout<<"----------\n";
	}
	for(int i=1;i<=m;i++)
	{
		cout<<ans[a[i]][1]<<" "<<ans[a[i]][2]<<" "<<ans[a[i]][3]<<" "<<ans[a[i]][4]<<"\n";
	}
	return 0;
}
